<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import PageHeader from '@/components/PageHeader.vue'
import StatusTag from '@/components/StatusTag.vue'
import type { Template } from '@/types'
import { createTemplate, deleteTemplate, getTemplates, updateTemplate } from '@/api/templates'
import { ElMessage, ElMessageBox } from 'element-plus'

const fieldOptions = [
  { label: '学生姓名', value: 'student_name' },
  { label: '证书编号', value: 'certificate_no' },
  { label: '成绩等级', value: 'grade_level' },
  { label: '导师签章', value: 'mentor_signature' },
  { label: '签发日期', value: 'issue_date' },
  { label: '验真二维码', value: 'qr_code' }
]
const fieldLabel = (value: string) => fieldOptions.find(x => x.value === value)?.label || value
const emptyTemplate = (): Template => ({ template_id: 0, name: '', issuer: '', course_name: '', project_name: '', certificate_title: '实训结业证书', content: '该生已完成规定的实训课程，考核合格，特发此证。', issue_year: String(new Date().getFullYear()), fields: ['student_name','certificate_no','issue_date','qr_code'], enabled: true, updated_at: '' })
const loading=ref(false),dialog=ref(false),preview=ref(false),rows=ref<Template[]>([]),total=ref(0),current=ref<Template>()
const query=reactive({current:1,size:10,keyword:'',status:''})
const form=reactive<Template>(emptyTemplate())
async function load(){loading.value=true;try{const p=await getTemplates(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}
function reset(){query.keyword='';query.status='';query.current=1;load()}
function open(row?:Template){Object.assign(form,row?JSON.parse(JSON.stringify(row)):emptyTemplate());dialog.value=true}
function show(row:Template){current.value=row;preview.value=true}
async function save(){if(!form.name||!form.issuer||!form.project_name||!form.certificate_title)return ElMessage.warning('请填写模板名称、签发机构、项目名称和证书标题');if(!form.fields.length)return ElMessage.warning('请至少选择一个证书字段');if(form.template_id)await updateTemplate(form.template_id,form);else await createTemplate(form);ElMessage.success('模板保存成功');dialog.value=false;load()}
async function remove(row:Template){await ElMessageBox.confirm(`确认删除模板“${row.name}”吗？`,'删除模板',{type:'warning'});await deleteTemplate(row.template_id);ElMessage.success('删除成功');load()}
onMounted(load)
</script>
<template><div><PageHeader title="证书模板管理" description="配置证书内容、动态字段、签发机构和验真信息"><el-button type="primary" @click="open()">新建模板</el-button></PageHeader><section class="panel"><div class="template-guide"><div><b>模板字段配置</b><span>学生姓名、编号、成绩、导师签章、日期和二维码可按需组合</span></div><div><b>生成与验真</b><span>模板将用于批量生成PDF，并在证书中嵌入验真二维码</span></div></div><div class="toolbar"><el-input v-model="query.keyword" placeholder="模板、课程、项目或机构" clearable style="width:280px" @keyup.enter="query.current=1;load()"/><el-select v-model="query.status" placeholder="状态" clearable style="width:140px"><el-option label="启用" value="ENABLED"/><el-option label="停用" value="DISABLED"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无证书模板"><el-table-column prop="name" label="模板名称" min-width="190"/><el-table-column prop="course_name" label="课程名称" min-width="170"/><el-table-column prop="project_name" label="项目名称" min-width="190"/><el-table-column prop="issuer" label="签发机构" min-width="150"/><el-table-column label="配置字段" width="100"><template #default="s">{{s.row.fields.length}}项</template></el-table-column><el-table-column label="状态" width="90"><template #default="s"><StatusTag :value="s.row.enabled?'ENABLED':'DISABLED'"/></template></el-table-column><el-table-column prop="updated_at" label="更新时间" min-width="160"/><el-table-column label="操作" width="190" fixed="right"><template #default="s"><el-button link type="primary" @click="show(s.row)">预览</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-dialog v-model="dialog" :title="form.template_id?'编辑证书模板':'新建证书模板'" width="760"><el-form label-position="top"><div class="form-grid"><el-form-item label="模板名称" required><el-input v-model="form.name" placeholder="如：暑期实训结业证书"/></el-form-item><el-form-item label="签发机构" required><el-input v-model="form.issuer" placeholder="如：示范学院"/></el-form-item><el-form-item label="课程名称"><el-input v-model="form.course_name" placeholder="如：软件开发综合实训"/></el-form-item><el-form-item label="项目名称" required><el-input v-model="form.project_name" placeholder="如：2026暑期软件开发实训"/></el-form-item><el-form-item label="证书标题" required><el-input v-model="form.certificate_title"/></el-form-item><el-form-item label="签发年度"><el-input v-model="form.issue_year"/></el-form-item></div><el-form-item label="证书正文"><el-input v-model="form.content" type="textarea" :rows="4" maxlength="300" show-word-limit/></el-form-item><el-form-item label="证书动态字段" required><el-checkbox-group v-model="form.fields" class="field-options"><el-checkbox v-for="item in fieldOptions" :key="item.value" :value="item.value">{{item.label}}</el-checkbox></el-checkbox-group></el-form-item><el-form-item label="模板状态"><el-switch v-model="form.enabled" active-text="启用" inactive-text="停用"/></el-form-item><div class="mini-preview"><h3>{{form.certificate_title||'证书标题'}}</h3><p>{{form.content||'证书正文将在此处预览'}}</p><div><span v-for="field in form.fields" :key="field">{{fieldLabel(field)}}</span></div></div></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存模板</el-button></template></el-dialog><el-drawer v-model="preview" title="证书模板预览" size="680"><div v-if="current" class="certificate-preview"><div class="certificate-border"><div class="certificate-seal">{{current.issuer.slice(0,1)}}</div><p class="certificate-year">{{current.issue_year}} · CERTIFICATE</p><h2>{{current.certificate_title}}</h2><p class="certificate-recipient" v-if="current.fields.includes('student_name')">张三 同学：</p><p class="certificate-body">{{current.content}}</p><div class="certificate-meta"><span>课程：{{current.course_name||'—'}}</span><span>项目：{{current.project_name}}</span><span v-if="current.fields.includes('grade_level')">成绩等级：优秀</span><span v-if="current.fields.includes('certificate_no')">证书编号：CERT-20260714-0001</span></div><div class="certificate-footer"><div><b>{{current.issuer}}</b><span v-if="current.fields.includes('issue_date')">2026年7月14日</span><span v-if="current.fields.includes('mentor_signature')">导师签章：________</span></div><div v-if="current.fields.includes('qr_code')" class="qr-placeholder">验真<br/>二维码</div></div></div></div><div class="configured-fields" v-if="current"><b>已配置字段</b><el-tag v-for="field in current.fields" :key="field" effect="plain">{{fieldLabel(field)}}</el-tag></div></el-drawer></div></template>